style.scss:
$violet-glow: rgba(147, 51, 234, 0.18);
$cyan-glow: rgba(59, 130, 246, 0.14);
$frost-line: rgba(191, 219, 254, 0.14);

body.theme-aurora-cascade {
  background-image:
    radial-gradient(circle at top left, $violet-glow, transparent 32%),
    radial-gradient(circle at top right, $cyan-glow, transparent 28%),
    linear-gradient(180deg, rgba(22, 32, 56, 0.95), rgba(15, 23, 42, 1));

  .panel,
  .modal {
    background: linear-gradient(180deg, rgba(27, 40, 70, 0.96), rgba(22, 32, 56, 0.94));
    border-color: $frost-line;
  }

  .btn,
  .chip,
  .settings-pill,
  .addons-tab {
    border-radius: 999px;
  }

  .btn-accent {
    background: linear-gradient(135deg, #7c3aed, #3b82f6);
    color: #f8fbff;
  }

  .page-title,
  h1,
  h2,
  h3 {
    letter-spacing: 0.015em;
  }

  .modal {
    .modal-header,
    .modal-footer {
      border-color: rgba(148, 163, 184, 0.16);
    }
  }
}

